export type TypeFormat = "TRIPLETTE" | "DOUBLETTE" | "TÊTE À TÊTE" | "ENDURO" | "AUTRE";
export type TypeCategorie =
  | "SÉNIOR"
  | "VÉTÉRAN"
  | "FÉMININ"
  | "MIXTE"
  | "JEUNES"
  | "PROMOTION"
  | "JEU PROVENÇAL"
  | "CHAMPIONNAT"
  | "OPEN"
  | "RÉGIONAL"
  | "NATIONAL";

export interface ConcourAllier {
  id: number;
  date: string;          // ISO date YYYY-MM-DD
  dateFin?: string;      // ISO date si multi-jours
  ville: string;
  lieu?: string;         // Boulodrome / salle précise
  club: string;          // Nom du club organisateur
  format: TypeFormat;
  categorie: string;     // Description libre (Triplette Vétéran, Doublette Mixte…)
  info?: string;         // Infos complémentaires (limite, heure, nocturne…)
  lat: number;
  lng: number;
  type: "CONCOURS" | "CHAMPIONNAT" | "RÉGIONAL" | "NATIONAL" | "SPÉCIAL";
}

