// Utilitaire : filtrer par mois
export function getConcoursByMonth(month: number, year: number): ConcourAllier[] {
  return CONCOURS_ALLIER_2026.filter(c => {
    const d = new Date(c.date);
    return d.getMonth() + 1 === month && d.getFullYear() === year;
  });
}

// Utilitaire : filtrer par ville
export function getConcoursByVille(ville: string): ConcourAllier[] {
  return CONCOURS_ALLIER_2026.filter(c =>
    c.ville.toLowerCase().includes(ville.toLowerCase())
  );
}

// Utilitaire : filtrer par type
export function getConcoursByType(type: ConcourAllier["type"]): ConcourAllier[] {
  return CONCOURS_ALLIER_2026.filter(c => c.type === type);
}
